module matrix_mult (
    input [3:0] A00, A01, // First row of first matrix
    input [3:0] A10, A11, // Second row of first matrix
    input [3:0] B00, B01, // First row of second matrix
    input [3:0] B10, B11, // Second row of second matrix
    output [3:0] C00, C01, // First row of result matrix
    output [3:0] C10, C11  // Second row of result matrix
);
    // Matrix multiplication
      wire _n01 = A00 * B00[0] ^ A01 * B10[0];
  wire _c01 = A00 * B00[0] & A01 * B10[0];
  wire _n02 = A00 * B00[1] ^ A01 * B10[1] ^ _c01;
  wire _c02 = (A00 * B00[1] & A01 * B10[1]) | (A00 * B00[1] & _c01) | (A01 * B10[1] & _c01);
  wire _n03 = A00 * B00[2] ^ A01 * B10[2] ^ _c02;
  wire _c03 = (A00 * B00[2] & A01 * B10[2]) | (A00 * B00[2] & _c02) | (A01 * B10[2] & _c02);
  wire _n04 = A00 * B00[3] ^ A01 * B10[3] ^ _c03;
  wire _c04 = (A00 * B00[3] & A01 * B10[3]) | (A00 * B00[3] & _c03) | (A01 * B10[3] & _c03);
  assign C00 = {_n01, _n02, _n03, _n04}; // C[0][0]
    assign C01 = A00 * B01 + A01 * B11; // C[0][1]
    assign C10 = A10 * B00 + A11 * B10; // C[1][0]
    assign C11 = A10 * B01 + A11 * B11; // C[1][1]
endmodule
